export default function Skills() {
  const sectionRef = useRef<HTMLElement>(null)
  const categoriesRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    const ctx = gsap.context(() => {
      const badges = categoriesRef.current?.querySelectorAll('.skill-badge') ?? []
      gsap.fromTo(
        badges,
        { opacity: 0, y: 24, scale: 0.88 },
        {
          opacity: 1,
          y: 0,
          scale: 1,
          stagger: 0.045,
          duration: 0.55,
          ease: 'back.out(1.4)',
          scrollTrigger: {
            trigger: categoriesRef.current,
            start: 'top 75%',
            toggleActions: 'play none none none',
          },
        }
      )

      const headings = categoriesRef.current?.querySelectorAll('.category-heading') ?? []
      gsap.fromTo(
        headings,
        { opacity: 0, x: -20 },
        {
          opacity: 1,
          x: 0,
          stagger: 0.12,
          duration: 0.6,
          ease: 'power3.out',
          scrollTrigger: {
            trigger: categoriesRef.current,
            start: 'top 75%',
            toggleActions: 'play none none none',
          },
        }
      )
    }, sectionRef)

    return () => ctx.revert()
  }, [])

  return (
    <section
      id="skills"
      ref={sectionRef}
      className="py-24 md:py-32 bg-[#060606] relative overflow-hidden"
    >
      {/* Subtle background grid */}
      <div
        className="absolute inset-0 pointer-events-none opacity-[0.025]"
        style={{
          backgroundImage:
            'linear-gradient(rgba(201,168,76,0.8) 1px, transparent 1px), linear-gradient(90deg, rgba(201,168,76,0.8) 1px, transparent 1px)',
          backgroundSize: '60px 60px',
        }}
        aria-hidden="true"
      />

      <div className="relative z-10 max-w-7xl mx-auto px-6">
        {/* Header */}
        <div className="text-center mb-16">
          <p className="text-xs text-[#C9A84C] font-bold uppercase tracking-[0.25em] mb-4">
            Tecnologías
          </p>
          <h2 className="text-4xl md:text-5xl lg:text-6xl font-extrabold text-[#F5F5F3] tracking-tight mb-5">
            Nuestro stack
          </h2>
          <p className="text-[#F5F5F3]/55 text-lg max-w-xl mx-auto leading-relaxed">
            Trabajamos con las herramientas más modernas del mercado para
            garantizar webs rápidas, seguras y escalables.
          </p>
        </div>

        {/* Animated card preview */}
        <div className="mb-20">
          <AnimatedCardStack />
        </div>

        {/* Categories */}
        <div ref={categoriesRef} className="space-y-12">
          {categories.map((cat) => (
            <div key={cat.label} className="flex flex-col md:flex-row md:items-start gap-6 md:gap-10">
              {/* Category label */}
              <div className="category-heading flex-shrink-0 w-full md:w-36 opacity-0">
                <span className="text-xs font-bold uppercase tracking-[0.2em] text-[#F5F5F3]/30">
                  {cat.label}
                </span>
                <div className="mt-2 h-px w-8 bg-[rgba(201,168,76,0.3)]" />
              </div>

              {/* Skill badges */}
              <div className="flex flex-wrap gap-3">
                {cat.skills.map((skill) => (
                  <div
                    key={skill.name}
                    className="skill-badge group flex items-center gap-2.5 px-4 py-2.5 rounded-xl border border-[rgba(255,255,255,0.07)] bg-[#0D0D0D] hover:border-[rgba(201,168,76,0.3)] hover:bg-[#111] transition-all duration-250 cursor-default opacity-0"
                    style={{ '--skill-color': skill.color } as React.CSSProperties}
                  >
                    {/* Icon */}
                    <span
                      className="flex-shrink-0 transition-colors duration-250"
                      style={{ color: skill.color, opacity: 0.85 }}
                    >
                      {skill.icon}
                    </span>
                    {/* Name */}
                    <span className="text-sm font-semibold text-[#F5F5F3]/75 group-hover:text-[#F5F5F3] transition-colors duration-200 whitespace-nowrap">
                      {skill.name}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}
